INSERT OR IGNORE INTO mangas (id,title,author,cover_url,total_chapters,current_chapter,status,rating,genre,synopsis,reader_url,mangadex_id,favorite) VALUES ('94','Jujutsu Kaisen','Akutami Gege','https://uploads.mangadex.org/covers/c52b2ce3-7f95-469c-96b0-479524fb7a1a/6d9134b2-21ea-4d02-ac2b-7c0d1c6a2aaa.jpg.512.jpg','271','236','reading','4','Action, Adventure, Horror','Yuuji est un jeune étudiant qui excelle dans le sport, notamment dans l''athlétisme, mais qui a un immense poil dans la main. Du coup, au lieu de parfaire ses capacités physiques qui pourraient lui permettre de devenir le meilleur de l''établissement, il s''est inscrit au club de recherches occultes du lycée. Son petit train-train va changer du tout au tout lorsqu''un véritable esprit malfaiteur vient menacer son école…

---

Maison d''édition FR : **Ki-oon**','https://sushiscan.fr/catalogue/jujutsu-kaisen-modulo/',NULL,'0');
INSERT OR IGNORE INTO mangas (id,title,author,cover_url,total_chapters,current_chapter,status,rating,genre,synopsis,reader_url,mangadex_id,favorite) VALUES ('95','Vinland Saga','Yukimura, Makoto','https://cdn.myanimelist.net/images/manga/2/188925l.jpg','224','1','reading','5','Action, Adventure, Award Winning, Drama','Thorfinn, son of one of the Vikings'' greatest warriors, is among the finest fighters in the merry band of mercenaries run by the cunning Askeladd, an impressive feat for a person his age. However, Thorfinn is not part of the group for the plunder it entails—instead, for having caused his family great tragedy, the boy has vowed to kill Askeladd in a fair duel. Not yet skilled enough to defeat him, but unable to abandon his vengeance, Thorfinn spends his boyhood with the mercenary crew, honing his skills on the battlefield among the war-loving Danes, where killing is just another pleasure of life.

One day, when Askeladd receives word that Danish prince Canute has been taken hostage, he hatches an ambitious plot—one that will decide the next King of England and drastically alter the lives of Thorfinn, Canute, and himself. Set in 11th-century Europe, Vinland Saga tells a bloody epic in an era where violence, madness, and injustice are inescapable, providing a paradise for the battle-crazed and utter hell for the rest who live in it.

[Written by MAL Rewrite]

Included one-shots:
Volume 23: Sayounara ga Chikai node (For Our Farewell Is Near)
Volume 25: "Assassin''s Creed Valhalla" Collab Bangai-hen (Assassin''s Creed x Vinland Saga)','https://sushiscan.fr/catalogue/saga-vinland/',NULL,'0');
